// ============================================================
// src/components/GameScreen.jsx
// The main describe phase — shows word, timer, input
// ============================================================
import React, { useState, useEffect, useRef } from "react";
import socket from "../socket";

export default function GameScreen({ game, player, onVoting, onResult }) {
  const [wordInfo, setWordInfo]       = useState(null);   // { word, isImpostor, round, totalRounds }
  const [description, setDescription]= useState("");
  const [submitted, setSubmitted]     = useState(false);
  const [submitCount, setSubmitCount] = useState({ submitted: 0, total: 0 });
  const [timeLeft, setTimeLeft]       = useState(60);
  const [phase, setPhase]             = useState("describe"); // describe | waiting
  const inputRef = useRef(null);

  useEffect(() => {
    // Receive secret word
    socket.on("yourWord", (data) => {
      setWordInfo(data);
      setDescription("");
      setSubmitted(false);
      setTimeLeft(60);
      setPhase("describe");
      setTimeout(() => inputRef.current?.focus(), 300);
    });

    // Timer ticks from server
    socket.on("timerTick", ({ secondsLeft }) => setTimeLeft(secondsLeft));

    // How many players have submitted
    socket.on("descriptionUpdate", (data) => setSubmitCount(data));

    // Move to voting
    socket.on("votingStarted", (data) => onVoting(data));

    // Move to result (in case this client missed votingStarted)
    socket.on("roundResult", (data) => onResult(data));

    return () => {
      socket.off("yourWord");
      socket.off("timerTick");
      socket.off("descriptionUpdate");
      socket.off("votingStarted");
      socket.off("roundResult");
    };
  }, [onVoting, onResult]);

  const handleSubmit = () => {
    if (!description.trim() || submitted) return;
    socket.emit("submitDescription", {
      code: game.code,
      playerId: player._id,
      playerName: player.name,
      text: description.trim(),
    });
    setSubmitted(true);
    setPhase("waiting");
  };

  const timerColor = timeLeft > 30 ? "#2ec4b6" : timeLeft > 10 ? "#f4a261" : "#e63946";
  const timerPct   = (timeLeft / 60) * 100;

  if (!wordInfo) return (
    <div className="screen centered">
      <div className="spinner" />
      <p className="muted">Waiting for round to begin…</p>
    </div>
  );

  return (
    <div className="screen">
      {/* Top bar */}
      <header className="topbar">
        <span className="logo-sm">IMPOSTOR<span>·X</span></span>
        <span className="round-badge">Round {wordInfo.round} / {wordInfo.totalRounds}</span>
        <span className="timer-display" style={{ color: timerColor }}>⏱ {timeLeft}s</span>
      </header>

      {/* Timer bar */}
      <div className="timer-track">
        <div className="timer-fill" style={{ width: `${timerPct}%`, background: timerColor }} />
      </div>

      <div className="game-layout">
        {/* Word card */}
        <div className="card word-card">
          <p className="word-label">{wordInfo.isImpostor ? "YOUR ROLE" : "SECRET WORD"}</p>
          <h1 className={`big-word ${wordInfo.isImpostor ? "impostor-word" : ""}`}>
            {wordInfo.word}
          </h1>
          {wordInfo.isImpostor
            ? <p className="word-hint">🕵️ You are the impostor! Blend in — describe something plausible.</p>
            : <p className="word-hint">💬 Describe this word in ONE short sentence without saying it directly.</p>
          }
        </div>

        {/* Input / submitted */}
        <div className="card describe-card">
          {phase === "describe" ? (
            <>
              <h3>Your Description</h3>
              <textarea
                ref={inputRef}
                className="desc-input"
                placeholder={wordInfo.isImpostor
                  ? "e.g. It can be found near water…"
                  : "e.g. It looks blue and moves slowly…"}
                maxLength={120}
                value={description}
                onChange={e => setDescription(e.target.value)}
                onKeyDown={e => e.key === "Enter" && !e.shiftKey && handleSubmit()}
              />
              <div className="desc-footer">
                <span className="char-count">{description.length}/120</span>
                <button className="btn primary" onClick={handleSubmit} disabled={!description.trim()}>
                  Submit ✓
                </button>
              </div>
            </>
          ) : (
            <div className="submitted-state">
              <div className="check-icon">✓</div>
              <p>Description submitted!</p>
              <p className="muted">{submitCount.submitted} / {submitCount.total} players submitted</p>
              <div className="dot-loader"><span/><span/><span/></div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
